// ─── NORMALIZE — Uses pre-extracted fields from search-apis ───
const items = $input.all();

const normalized = items.map((item, index) => {
  const d = item.json;
  if (d.error || d._empty) return null;

  const src = d._source || d.source || 'unknown';
  const originalId = d.id || '';

  // Use pre-extracted fields from search-apis (already normalized)
  let title = d.title || d.display_name || '';
  let abstract = d.abstract || '';
  let authors = Array.isArray(d.authors) ? d.authors : [];
  let year = d.year ? String(d.year) : '';
  let journal = d.journal || '';
  let doi = d.doi || '';

  // Fallback: try source-specific raw fields ONLY if pre-extracted are empty
  if (src === 'openalex') {
    if (!title) title = d.display_name || '';
    if (authors.length === 0 && d.authorships) {
      authors = (d.authorships || []).map(a => (a.author && a.author.display_name) || '').filter(Boolean);
    }
    if (!year && d.publication_year) year = String(d.publication_year);
    if (!journal && d.primary_location && d.primary_location.source) {
      journal = d.primary_location.source.display_name || '';
    }
    if (!abstract && d.abstract_inverted_index && typeof d.abstract_inverted_index === 'object') {
      const words = {};
      Object.keys(d.abstract_inverted_index).forEach(word => {
        const positions = d.abstract_inverted_index[word];
        if (Array.isArray(positions)) positions.forEach(pos => { words[pos] = word; });
      });
      abstract = Object.keys(words).sort((a, b) => Number(a) - Number(b)).map(k => words[k]).join(' ');
    }
  } else if (src === 'crossref') {
    if (!title && Array.isArray(d.title)) title = d.title[0] || '';
    if (authors.length === 0 && d.author) {
      authors = (d.author || []).map(a => ((a.given || '') + ' ' + (a.family || '')).trim()).filter(Boolean);
    }
    if (!year && d.published && d.published['date-parts'] && d.published['date-parts'][0]) {
      year = String(d.published['date-parts'][0][0] || '');
    }
    if (!journal && d['container-title']) {
      journal = Array.isArray(d['container-title']) ? d['container-title'][0] : (d['container-title'] || '');
    }
    if (!doi && d.DOI) doi = d.DOI;
  }

  // Clean DOI format
  if (doi && doi.startsWith('https://doi.org/')) doi = doi.replace('https://doi.org/', '');

  // Construct article URL
  let url = '';
  if (doi) {
    url = 'https://doi.org/' + doi;
  } else if (originalId && originalId.startsWith('https://')) {
    url = originalId;
  } else if (originalId && originalId.startsWith('pmid:')) {
    url = 'https://pubmed.ncbi.nlm.nih.gov/' + originalId.replace('pmid:', '');
  }

  if (!title || !title.trim()) return null;

  return {
    json: {
      id: doi ? 'doi:' + doi : (originalId || src + ':' + index),
      title: title.trim(),
      abstract: abstract.trim(),
      authors,
      year,
      journal,
      doi,
      url,
      source: src,
      question: d.question || '',
      criteria: d.criteria || '',
      search_query: d.search_query || '',
      pubmed_query: d.pubmed_query || '',
      openalex_query: d.openalex_query || '',
      crossref_query: d.crossref_query || '',
      output_folder: d.output_folder || '',
      prefilter_enabled: d.prefilter_enabled,
      prefilter_count: d.prefilter_count,
      max_results: d.max_results
    }
  };
}).filter(item => item !== null);

console.log('Normalized: ' + normalized.length + ' articles (filtered from ' + items.length + ')');
const withAuthors = normalized.filter(n => n.json.authors.length > 0).length;
const withYear = normalized.filter(n => n.json.year).length;
const withDoi = normalized.filter(n => n.json.doi).length;
const withUrl = normalized.filter(n => n.json.url).length;
console.log('  Authors: ' + withAuthors + '/' + normalized.length + ' | Year: ' + withYear + ' | DOI: ' + withDoi + ' | URL: ' + withUrl);
return normalized;

// ─── Save complete RIS of ALL articles from API (before screening) ───
const fs = require('fs');
const path = require('path');
const items = $input.all();
const articles = items.map(i => i.json);
const outputFolder = (articles[0] && articles[0].output_folder) || '/desktop/review ultralab';

let ris = '';
articles.forEach(a => {
  ris += 'TY  - JOUR\n';
  ris += 'TI  - ' + (a.title || '').replace(/\n/g, ' ') + '\n';
  if (Array.isArray(a.authors)) a.authors.forEach(au => { ris += 'AU  - ' + au + '\n'; });
  if (a.year) ris += 'PY  - ' + a.year + '\n';
  if (a.journal) ris += 'JO  - ' + (a.journal || '').replace(/\n/g, ' ') + '\n';
  if (a.doi) ris += 'DO  - ' + a.doi + '\n';
  if (a.url) ris += 'UR  - ' + a.url + '\n';
  if (a.abstract) ris += 'AB  - ' + (a.abstract || '').replace(/\n/g, ' ').substring(0, 2000) + '\n';
  if (a.source) ris += 'DB  - ' + a.source + '\n';
  ris += 'ER  -\n\n';
});

try {
  fs.mkdirSync(outputFolder, { recursive: true });
  fs.writeFileSync(path.join(outputFolder, 'articles_complet_API.ris'), ris, 'utf-8');
  console.log('Saved articles_complet_API.ris: ' + articles.length + ' articles to ' + outputFolder);
} catch(e) {
  console.log('Save RIS error: ' + e.message);
}

// Pass all articles through unchanged
return items;
